import { tags } from 'decantr/tags';
import { createSignal } from 'decantr/state';
import { css } from 'decantr/css';
import { Button, Badge, Card, icon } from 'decantr/components';

code.example:
function PricingUsage({ tiers, faqs }) {
  const { div, section, h2, h3, p, span, input, table, thead, tbody, tr, th, td } = tags;
  const [annual, setAnnual] = createSignal(false);
  const [usage, setUsage] = createSignal(1000);

  const price = (tier) => annual() ? tier.annual : tier.monthly;
  const estimate = () => {
    const tier = tiers.find(t => usage() <= t.limit) || tiers[tiers.length - 1];
    return (usage() * tier.perUnit).toFixed(2);
  };

  return section({ class: css('_flex _col _gap12 _py16 _px6 _maxw[1200px] _mx[auto]') },
    div({ class: css('_tc _mb8') },
      h2({ class: css('_heading2 _mb4') }, 'Simple, usage-based pricing'),
      p({ class: css('_fgmuted _textlg') }, 'Pay only for what you use. No hidden fees.')
    ),
    div({ class: css('_flex _jcc _gap2 _mb8') },
      Button({ variant: annual() ? 'ghost' : 'primary', onclick: () => setAnnual(false) }, 'Monthly'),
      Button({ variant: annual() ? 'primary' : 'ghost', onclick: () => setAnnual(true) },
        'Annual', Badge({ variant: 'success', size: 'xs', class: css('_ml2') }, 'Save 20%')
      )
    ),
    div({ class: css('_grid _gc1 _md:gc3 _gap6') },
      ...tiers.map((tier, i) =>
        Card({ class: css(`carbon-card _p6 ${tier.popular ? '_border[2px] _borderPrimary' : ''}`) },
          tier.popular ? Badge({ class: css('_mb4') }, 'Most Popular') : null,
          h3({ class: css('_heading4 _mb2') }, tier.name),
          div({ class: css('_flex _aic _gap1 _mb4') },
            span({ class: css('_heading1') }, `$${price(tier)}`),
            span({ class: css('_fgmuted') }, `/${annual() ? 'year' : 'month'}`)
          ),
          p({ class: css('_fgmuted _mb6') }, tier.description),
          Button({ variant: tier.popular ? 'primary' : 'outline', class: css('_wfull _mb6') },
            'Get Started'
          ),
          div({ class: css('_flex _col _gap2') },
            ...tier.features.map(f =>
              div({ class: css('_flex _aic _gap2') },
                icon('check', { size: '16', class: css('_fgSuccess') }),
                span({}, f)
              )
            )
          )
        )
      )
    ),
    div({ class: css('carbon-card _p8 _r3 _mt8') },
      h3({ class: css('_heading4 _mb4') }, 'Estimate your monthly cost'),
      div({ class: css('_flex _aic _gap4') },
        input({
          type: 'range',
          min: 0,
          max: 100000,
          value: usage(),
          oninput: (e) => setUsage(Number(e.target.value)),
          class: css('_flex1')
        }),
        span({ class: css('_heading3 _minw[120px] _tr') }, `$${estimate()}`)
      ),
      p({ class: css('_fgmuted _mt2') }, `${usage().toLocaleString()} API calls/month`)
    )
  );
}

