function CompactPricing({ tiers }) {
  const { div, h2, h3, span } = tags;

  return div({ class: css('_grid _gc1 _md:gc3 _gap6 _py12 _px6') },
    ...tiers.map(tier =>
      Card({ class: css('carbon-card _p6') },
        h3({ class: css('_heading4') }, tier.name),
        span({ class: css('_heading2') }, `$${tier.price}`),
        Button({ variant: 'outline', class: css('_wfull _mt4') }, 'Choose')
      )
    )
  );
}

